const express = require('express');
const twilio = require('twilio')(accountSid, authToken);
const session = require('express-session')({
  secret: 'your secret key',
  resave: false,
  saveUninitialized: true,
});

const app = express();
app.use(session);

// Generate random 6-digit code and send via SMS
app.post('/sendCode', (req, res) => {
  const code = Math.floor(Math.random() * 1000000).toString().substr(1);
  twilio.messages.create({
    to: req.body.phoneNumber,
    from: 'your Twilio number',
    body: `Your verification code is ${code}.`,
  }).then(() => {
    req.session.code = code;
    res.sendStatus(201);
  });
});

// Verify user input and log in if valid
app.post('/verify', (req, res) => {
  const userInput = req.body.verificationCode;
  const expectedCode = req.session.code;
  if (userInput === expectedCode) {
    // Log in the user
    res.sendStatus(200);
  } else {
    res.status(401).send('Invalid verification code');
  }
});